LIQUID_ETFS = [
    Instrument("NIFTYBEES",  "Nippon Nifty BeES ETF",  AssetClass.ETF, Exchange.NSE, dhan_security_id="6191",  segment="Broad"),
    Instrument("BANKBEES",   "Nippon Bank BeES ETF",   AssetClass.ETF, Exchange.NSE, dhan_security_id="8382",  segment="Banking"),
    Instrument("GOLDBEES",   "Nippon Gold BeES ETF",   AssetClass.ETF, Exchange.NSE, dhan_security_id="8869",  segment="Gold"),
    Instrument("JUNIORBEES", "Nippon Junior BeES ETF", AssetClass.ETF, Exchange.NSE, dhan_security_id="7203",  segment="Midcap"),
    Instrument("ITBEES",     "Nippon IT BeES ETF",     AssetClass.ETF, Exchange.NSE, dhan_security_id="14428", segment="IT"),
    Instrument("CPSEETF",    "CPSE ETF",               AssetClass.ETF, Exchange.NSE, dhan_security_id="19923", segment="PSU"),
]


def get_equity_universe() -> list[Instrument]:
    return NIFTY500_STOCKS


def get_index_universe() -> list[Instrument]:
    return BROAD_INDICES + SECTORAL_INDICES


def get_commodity_universe() -> list[Instrument]:
    return COMMODITIES


def get_fno_universe() -> list[Instrument]:
    return NIFTY50_STOCKS + [
        i for i in BROAD_INDICES if i.symbol in ("NIFTY", "BANKNIFTY", "FINNIFTY", "MIDCPNIFTY")
    ]


def get_etf_universe() -> list[Instrument]:
    return LIQUID_ETFS


def get_full_universe() -> list[Instrument]:
    return get_equity_universe() + get_index_universe() + get_commodity_universe() + get_etf_universe()


def get_universe_by_segment(segment: str) -> list[Instrument]:
    return [i for i in get_full_universe() if i.segment == segment]


ALL_SEGMENTS = sorted(set(i.segment for i in get_full_universe() if i.segment))
